import React, { useState, useEffect } from 'react';
import { dishAPI, restaurantAPI } from '../services/api';

const OwnerDashboard = ({ user, onLogout }) => {
  const [dishes, setDishes] = useState([]);
  const [restaurants, setRestaurants] = useState([]);
  const [ownerRestaurant, setOwnerRestaurant] = useState(null);
  const [showAddForm, setShowAddForm] = useState(false);
  const [showRestaurantForm, setShowRestaurantForm] = useState(false);
  const [editingDish, setEditingDish] = useState(null);
  const [restaurantData, setRestaurantData] = useState({
    name: '',
    location: '',
    phone: '',
    description: '',
    imageUrl: '',
    ownerId: user.id
  });
  const [showEditRestaurant, setShowEditRestaurant] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    price: '',
    category: '',
    imageUrl: ''
  });
  const [selectedFile, setSelectedFile] = useState(null);
  const [uploading, setUploading] = useState(false);

  useEffect(() => {
    loadDishes();
    loadRestaurants();
  }, []);

  const loadDishes = async () => {
    try {
      const response = await dishAPI.getAll();
      setDishes(response.data);
    } catch (error) {
      console.error('Error loading dishes:', error);
    }
  };

  const loadRestaurants = async () => {
    try {
      const response = await restaurantAPI.getAll();
      setRestaurants(response.data);
      // Find owner's restaurant
      const userRestaurant = response.data.find(r => r.ownerId === user.id);
      setOwnerRestaurant(userRestaurant);
      if (!userRestaurant) {
        setShowRestaurantForm(true);
      }
    } catch (error) {
      console.error('Error loading restaurants:', error);
    }
  };

  const handleFileChange = (e) => {
    setSelectedFile(e.target.files[0]);
  };

  const uploadImage = async () => {
    if (!selectedFile) return null;

    setUploading(true);
    const formDataUpload = new FormData();
    formDataUpload.append('file', selectedFile);

    try {
      const response = await fetch('http://localhost:8080/api/upload/image', {
        method: 'POST',
        body: formDataUpload,
      });
      const result = await response.json();
      setUploading(false);
      return result.imageUrl;
    } catch (error) {
      setUploading(false);
      throw error;
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      let finalFormData = { ...formData };

      // Upload image if file is selected
      if (selectedFile) {
        const imageUrl = await uploadImage();
        finalFormData.imageUrl = 'http://localhost:8080' + imageUrl;
      }

      // Set restaurant ID to owner's restaurant
      if (ownerRestaurant) {
        finalFormData.restaurantId = ownerRestaurant.restaurantId;
      }

      if (editingDish) {
        await dishAPI.update(editingDish.dishId, finalFormData);
      } else {
        await dishAPI.add(finalFormData);
      }
      loadDishes();
      resetForm();
    } catch (error) {
      alert('Error saving dish: ' + (error.response?.data || 'Unknown error'));
    }
  };

  const handleEdit = (dish) => {
    setEditingDish(dish);
    setFormData({
      name: dish.name,
      description: dish.description,
      price: dish.price,
      category: dish.category,
      imageUrl: dish.imageUrl || '',
      restaurantId: dish.restaurantId
    });
    setShowAddForm(true);
  };

  const handleDelete = async (dishId) => {
    if (window.confirm('Are you sure you want to delete this dish?')) {
      try {
        await dishAPI.delete(dishId);
        loadDishes();
      } catch (error) {
        alert('Error deleting dish: ' + (error.response?.data || 'Unknown error'));
      }
    }
  };

  const resetForm = () => {
    setFormData({
      name: '',
      description: '',
      price: '',
      category: '',
      imageUrl: ''
    });
    setEditingDish(null);
    setShowAddForm(false);
    setSelectedFile(null);
  };

  const handleRestaurantSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await restaurantAPI.register(restaurantData);
      setOwnerRestaurant(response.data);
      setShowRestaurantForm(false);
      setRestaurantData({ name: '', location: '', phone: '', description: '', imageUrl: '', ownerId: user.id });
      loadRestaurants();
    } catch (error) {
      alert('Error registering restaurant: ' + (error.response?.data || 'Unknown error'));
    }
  };

  const getRestaurantName = (restaurantId) => {
    const restaurant = restaurants.find(r => r.restaurantId === restaurantId);
    return restaurant ? restaurant.name : 'Unknown Restaurant';
  };

  return (
    <div className="min-h-screen bg-gray-100">
      <nav className="bg-green-600 text-white p-4">
        <div className="container mx-auto flex justify-between items-center">
          <h1 className="text-xl font-bold">SnackSmart - Owner Dashboard</h1>
          <div className="flex items-center space-x-4">
            <span>Welcome, {user.username}!</span>
            <button
              onClick={onLogout}
              className="bg-red-500 px-4 py-2 rounded hover:bg-red-600"
            >
              Logout
            </button>
          </div>
        </div>
      </nav>

      <div className="container mx-auto p-6">
        {showRestaurantForm ? (
          <div className="bg-white rounded-lg shadow-md p-6 mb-6">
            <h2 className="text-xl font-semibold mb-4">Register Your Restaurant</h2>
            <form onSubmit={handleRestaurantSubmit}>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <input
                  type="text"
                  placeholder="Restaurant Name"
                  className="px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                  value={restaurantData.name}
                  onChange={(e) => setRestaurantData({...restaurantData, name: e.target.value})}
                  required
                />
                <input
                  type="text"
                  placeholder="Restaurant Location"
                  className="px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                  value={restaurantData.location}
                  onChange={(e) => setRestaurantData({...restaurantData, location: e.target.value})}
                  required
                />
                <input
                  type="tel"
                  placeholder="Phone Number"
                  className="px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                  value={restaurantData.phone}
                  onChange={(e) => setRestaurantData({...restaurantData, phone: e.target.value})}
                />
                <input
                  type="url"
                  placeholder="Restaurant Image URL"
                  className="px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                  value={restaurantData.imageUrl}
                  onChange={(e) => setRestaurantData({...restaurantData, imageUrl: e.target.value})}
                />
              </div>
              <div className="mt-4">
                <textarea
                  placeholder="Restaurant Description"
                  className="w-full px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                  rows="3"
                  value={restaurantData.description}
                  onChange={(e) => setRestaurantData({...restaurantData, description: e.target.value})}
                />
              </div>
              <div className="mt-4">
                <button
                  type="submit"
                  className="bg-green-500 text-white px-4 py-2 rounded hover:bg-green-600"
                >
                  Register Restaurant
                </button>
              </div>
            </form>
          </div>
        ) : (
          <>
            {/* Restaurant Info */}
            {ownerRestaurant && (
              <div className="bg-white rounded-lg shadow-md p-6 mb-6">
                <div className="flex justify-between items-start">
                  <div className="flex-1">
                    <h2 className="text-2xl font-bold mb-2">{ownerRestaurant.name}</h2>
                    <p className="text-gray-600 mb-1">{ownerRestaurant.location}</p>
                    <p className="text-gray-600 mb-1">{ownerRestaurant.phone}</p>
                    <p className="text-gray-700 mb-3">{ownerRestaurant.description}</p>
                    <div className="flex items-center">
                      <span className="text-yellow-500 mr-2">★</span>
                      <span>{ownerRestaurant.averageRating?.toFixed(1) || '0.0'} Rating</span>
                    </div>
                  </div>
                  {ownerRestaurant.imageUrl && (
                    <img
                      src={ownerRestaurant.imageUrl}
                      alt={ownerRestaurant.name}
                      className="w-32 h-32 object-cover rounded-lg ml-4"
                    />
                  )}
                </div>
                <button
                  onClick={() => setShowEditRestaurant(!showEditRestaurant)}
                  className="mt-4 bg-gray-500 text-white px-4 py-2 rounded hover:bg-gray-600"
                >
                  {showEditRestaurant ? 'Cancel Edit' : 'Edit Restaurant Info'}
                </button>
              </div>
            )}

            {/* Edit Restaurant Form */}
            {showEditRestaurant && ownerRestaurant && (
              <div className="bg-white rounded-lg shadow-md p-6 mb-6">
                <h2 className="text-xl font-semibold mb-4">Edit Restaurant Information</h2>
                <form onSubmit={(e) => {
                  e.preventDefault();
                  // Handle restaurant update
                  restaurantAPI.update(ownerRestaurant.restaurantId, {
                    ...ownerRestaurant,
                    ...restaurantData
                  }).then(() => {
                    loadRestaurants();
                    setShowEditRestaurant(false);
                  }).catch(error => {
                    alert('Error updating restaurant: ' + (error.response?.data || 'Unknown error'));
                  });
                }}>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <input
                      type="text"
                      placeholder="Restaurant Name"
                      className="px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                      value={restaurantData.name || ownerRestaurant.name || ''}
                      onChange={(e) => setRestaurantData({...restaurantData, name: e.target.value})}
                    />
                    <input
                      type="text"
                      placeholder="Location"
                      className="px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                      value={restaurantData.location || ownerRestaurant.location || ''}
                      onChange={(e) => setRestaurantData({...restaurantData, location: e.target.value})}
                    />
                    <input
                      type="tel"
                      placeholder="Phone"
                      className="px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                      value={restaurantData.phone || ownerRestaurant.phone || ''}
                      onChange={(e) => setRestaurantData({...restaurantData, phone: e.target.value})}
                    />
                    <input
                      type="url"
                      placeholder="Image URL"
                      className="px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                      value={restaurantData.imageUrl || ownerRestaurant.imageUrl || ''}
                      onChange={(e) => setRestaurantData({...restaurantData, imageUrl: e.target.value})}
                    />
                  </div>
                  <textarea
                    placeholder="Description"
                    className="w-full mt-4 px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                    rows="3"
                    value={restaurantData.description || ownerRestaurant.description || ''}
                    onChange={(e) => setRestaurantData({...restaurantData, description: e.target.value})}
                  />
                  <div className="mt-4">
                    <button
                      type="submit"
                      className="bg-green-500 text-white px-4 py-2 rounded hover:bg-green-600 mr-2"
                    >
                      Update Restaurant
                    </button>
                  </div>
                </form>
              </div>
            )}

            <div className="mb-6">
              <button
                onClick={() => setShowAddForm(!showAddForm)}
                className="bg-blue-500 text-white px-4 py-2 rounded hover:bg-blue-600"
              >
                {showAddForm ? 'Cancel' : 'Add New Dish'}
              </button>
            </div>
          </>
        )}

        {showAddForm && (
          <div className="bg-white rounded-lg shadow-md p-6 mb-6">
            <h2 className="text-xl font-semibold mb-4">
              {editingDish ? 'Edit Dish' : 'Add New Dish'}
            </h2>
            <form onSubmit={handleSubmit}>
              {ownerRestaurant && (
                <div className="mb-4 p-3 bg-blue-50 rounded-lg">
                  <p className="text-sm text-blue-700">
                    Adding dish to: <strong>{ownerRestaurant.name}</strong>
                  </p>
                </div>
              )}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <input
                  type="text"
                  placeholder="Dish Name"
                  className="px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                  value={formData.name}
                  onChange={(e) => setFormData({...formData, name: e.target.value})}
                  required
                />
                <select
                  className="px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                  value={formData.category}
                  onChange={(e) => setFormData({...formData, category: e.target.value})}
                  required
                >
                  <option value="">Select Category</option>
                  <option value="VEG">Vegetarian</option>
                  <option value="NON_VEG">Non-Vegetarian</option>
                </select>
                <input
                  type="number"
                  step="0.01"
                  placeholder="Price"
                  className="px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                  value={formData.price}
                  onChange={(e) => setFormData({...formData, price: e.target.value})}
                  required
                />
                <div className="space-y-2">
                  <input
                    type="url"
                    placeholder="Image URL (optional)"
                    className="px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                    value={formData.imageUrl}
                    onChange={(e) => setFormData({...formData, imageUrl: e.target.value})}
                  />
                  <div className="text-center text-gray-500">OR</div>
                  <input
                    type="file"
                    accept="image/*"
                    onChange={handleFileChange}
                    className="px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                  />
                  {selectedFile && (
                    <p className="text-sm text-green-600">Selected: {selectedFile.name}</p>
                  )}
                </div>
              </div>
              <textarea
                placeholder="Description"
                className="w-full mt-4 px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                rows="3"
                value={formData.description}
                onChange={(e) => setFormData({...formData, description: e.target.value})}
              />
              <div className="mt-4 flex space-x-2">
                <button
                  type="submit"
                  disabled={uploading}
                  className="bg-green-500 text-white px-4 py-2 rounded hover:bg-green-600 disabled:bg-gray-400"
                >
                  {uploading ? 'Uploading...' : (editingDish ? 'Update' : 'Add') + ' Dish'}
                </button>
                <button
                  type="button"
                  onClick={resetForm}
                  className="bg-gray-500 text-white px-4 py-2 rounded hover:bg-gray-600"
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {dishes.map((dish) => (
            <div key={dish.dishId} className="bg-white rounded-lg shadow-md p-6">
              {dish.imageUrl && (
                <img
                  src={dish.imageUrl}
                  alt={dish.name}
                  className="w-full h-48 object-cover rounded-lg mb-4"
                />
              )}
              <h3 className="text-xl font-semibold mb-2">{dish.name}</h3>
              <p className="text-gray-600 mb-2">{dish.description}</p>
              <div className="flex items-center mb-2">
                {dish.category === 'VEG' ? 
                  <span className="inline-block w-4 h-4 bg-green-500 rounded-full mr-2"></span> :
                  <span className="inline-block w-4 h-4 bg-red-500 rounded-full mr-2"></span>
                }
                <span className="text-sm text-gray-500">{dish.category === 'VEG' ? 'Vegetarian' : 'Non-Vegetarian'}</span>
              </div>
              <p className="text-2xl font-bold text-green-600 mb-4">${dish.price}</p>
              <div className="flex space-x-2">
                <button
                  onClick={() => handleEdit(dish)}
                  className="bg-blue-500 text-white px-3 py-1 rounded hover:bg-blue-600"
                >
                  Edit
                </button>
                <button
                  onClick={() => handleDelete(dish.dishId)}
                  className="bg-red-500 text-white px-3 py-1 rounded hover:bg-red-600"
                >
                  Delete
                </button>
              </div>
            </div>
          ))}
        </div>

        {dishes.length === 0 && (
          <div className="text-center py-8">
            <p className="text-gray-500">No dishes found. Add your first dish!</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default OwnerDashboard;
